const body = $input.first().json.body ?? {};

const action = body.action || "listAll";
const params = body.params || {};

const allowed = ["add", "change", "deactivate", "activate", "listAll", "listActive"];

if (!allowed.includes(action)) {
  return [{
    json: {
      statusCode: 400,
      error: `Invalid action: ${action}`
    }
  }];
}

return [{
  json: {
    action,
    params,
    session_id: body.session_id || "researcher-ui",
    usecase_id: body.usecase_id || null,
    usecase_name: body.usecase_name || body.type || "Schedule",
    message: body.message || `Researcher UI schedule action: ${action}`
  }
}];

const input = $input.first().json;

const reply = input.reply ?? "";
const session_id = input.session_id ?? "researcher-ui";

// If Schedule Manager returned a non-list action response,
// return it as a normal status response.
if (!reply.includes("🆔")) {
  return [{
    json: {
      success: true,
      data: [],
      reply,
      session_id
    }
  }];
}

const schedules = [];

// Split each schedule block by the schedule ID marker
const blocks = reply
  .split("🆔")
  .slice(1); // first part is title/header

for (const block of blocks) {
  const idMatch = block.match(/\*ID\s+(\d+)\*/);
  const userMatch = block.match(/User:\s*(\d+)/);
  const typeMatch = block.match(/Type:\s*([a-zA-Z_]+)\s*\(([-+]?\d*\.?\d+)%\)/);
  const nextMatch = block.match(/Next Check:\s*(.*?)\s*\(Interval:\s*(\d+)\s*days?\)/);
  const activeMatch = block.match(/Active:\s*(true|false)/i);

  schedules.push({
    schedule_id: idMatch ? Number(idMatch[1]) : null,
    user_id: userMatch ? Number(userMatch[1]) : null,
    measure_type: typeMatch ? typeMatch[1] : null,
    trigger_percentage: typeMatch ? Number(typeMatch[2]) : null,
    next_check: nextMatch ? nextMatch[1].trim() : null,
    interval_days: nextMatch ? Number(nextMatch[2]) : null,
    active: activeMatch ? activeMatch[1].toLowerCase() === "true" : null
  });
}

return [{
  json: {
    success: true,
    data: schedules,
    reply,
    session_id
  }
}];

const input = $input.first().json;

// Accept userId from query, body, or root json
const query = input.query || {};
const body = input.body || {};

const userIdRaw =
  query.userId ??
  query.userid ??
  body.userId ??
  body.userid ??
  input.userId ??
  input.userid;

if (userIdRaw === undefined || userIdRaw === null || String(userIdRaw).trim() === "") {
  return [{
    json: {
      statusCode: 400,
      payload: {
        success: false,
        error: "Missing required userId parameter"
      }
    }
  }];
}

const userId = Number(userIdRaw);

if (!Number.isFinite(userId)) {
  return [{
    json: {
      statusCode: 400,
      payload: {
        success: false,
        error: "userId must be a number"
      }
    }
  }];
}

return [{
  json: {
    statusCode: 200,
    userId
  }
}];

const row = $input.first().json;

if (!row || Object.keys(row).length === 0 || !row.userid) {
  return [{
  json: {
    statusCode: 400,
    success: false,
    monitoringType: "Unknown",
    error: "Missing required userId parameter",
    payload: {
      success: false,
      error: "Missing required userId parameter"
    }
  }
}];
}

if (!row.active_usecase_id || !row.usecase_id) {
  return [{
    json: {
      statusCode: 404,
      payload: {
        success: false,
        userId: row.userid,
        error: "No use case assigned to this user"
      }
    }
  }];
}

return [{
  json: {
    statusCode: 200,

    // top-level for Android compatibility
    success: true,
    userId: row.userid,
    monitoringType: row.usecase_name,
    usecaseId: row.usecase_id,

    // nested version for cleaner API / future clients
    payload: {
      success: true,
      userId: row.userid,
      monitoringType: row.usecase_name,
      usecaseId: row.usecase_id,
      usecase: {
        id: row.usecase_id,
        monitoringType: row.usecase_name
      }
    }
  }
}];

