parameters.jsCode:
const baseline = $input.first().json.measure;
const schedule = $('Get Due Schedules').first().json;

// Tracking object for performance monitoring
const tracking = {
  user_id: schedule.user_id,
  interval_days: schedule.interval_days || 7,
  processed_at: new Date().toISOString(),
  status: 'calculated'
};

if (!baseline) {
  return [{ json: { ...tracking, status: 'skipped', reason: 'No sensor data' } }];
}

const minVal = Math.round(baseline * (1+0.01*$('Get Due Schedules').first().json.trigger_percentage));
const maxVal = minVal + 20;

return [{
  json: {
    ...tracking,
    minValue: minVal,
    maxValue: maxVal,
    type: $('Get Due Schedules').first().json.usecase_name,
    user_id: $('Get Due Schedules').first().json.user_id,
    active: true
  }
}];
